# Create the access package in the catalog
$pkgBody = @{
    displayName = 'Engineering Contractor Bundle'
    description = 'Group + app access for engineering contractors'
    catalog     = @{ id = $catalog.id }
    isHidden    = $false
} | ConvertTo-Json -Depth 5

$pkg = Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/entitlementManagement/accessPackages' \
  -Body $pkgBody -ContentType 'application/json'

# Add a resource role (group member) to the package
# First, get the resource and role IDs from the catalog
$resources = Invoke-MgGraphRequest -Method GET \
  -Uri "https://graph.microsoft.com/v1.0/identityGovernance/entitlementManagement/catalogs/$($catalog.id)/resources?`$expand=roles"

$groupResource = $resources.value | Where-Object { $_.originSystem -eq 'AadGroup' } | Select-Object -First 1
$memberRole    = $groupResource.roles | Where-Object { $_.displayName -eq 'Member' }

$roleBody = @{
    role     = @{ id = $memberRole.id; originId = $memberRole.originId; originSystem = 'AadGroup'
                  resource = @{ id = $groupResource.id; originId = $groupResource.originId; originSystem = 'AadGroup' } }
    resource = @{ id = $groupResource.id; originId = $groupResource.originId; originSystem = 'AadGroup' }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method POST \
  -Uri "https://graph.microsoft.com/v1.0/identityGovernance/entitlementManagement/accessPackages/$($pkg.id)/resourceRoleScopes" \
  -Body $roleBody -ContentType 'application/json'

# Policy: internal members, manager approval, 90-day duration, recurring access review
$policyBody = @{
    displayName  = 'Internal employee policy'
    description  = 'For FTE employees — manager must approve, access expires in 90 days'
    accessPackageId = $pkg.id
    requestorSettings = @{
        scopeType         = 'AllExistingDirectoryMemberUsers'
        acceptRequests    = $true
    }
    requestApprovalSettings = @{
        isApprovalRequired            = $true
        isApprovalRequiredForExtension = $false
        isRequestorJustificationRequired = $true
        approvalMode                  = 'SingleStage'
        approvalStages = @(
            @{
                approvalStageTimeOutInDays  = 14
                isApproverJustificationRequired = $true
                isEscalationEnabled         = $true
                escalationTimeInMinutes     = 10080
                primaryApprovers = @(
                    @{ '@odata.type' = '#microsoft.graph.requestorManager'; managerLevel = 1 }
                )
                escalationApprovers = @(
                    @{ '@odata.type' = '#microsoft.graph.singleUser'
                       id = '<fallback-approver-oid>' }
                )
            }
        )
    }
    accessReviewSettings = @{
        isEnabled             = $true
        recurrenceType        = 'quarterly'
        reviewerType          = 'Manager'
        startDateTime         = '2025-01-01T00:00:00Z'
        durationInDays        = 25
        isAccessRecommendationEnabled = $true
        isApprovalJustificationRequired = $true
        accessReviewTimeoutBehavior = 'removeAccess'
    }
    expiration = @{
        type     = 'afterDuration'
        duration = 'P90D'
    }
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/entitlementManagement/assignmentPolicies' \
  -Body $policyBody -ContentType 'application/json'

resource "azuread_access_package_catalog" "eng" {
  display_name = "Engineering Resources"
  description  = "Catalog for engineering team access"
}

resource "azuread_access_package" "contractor" {
  catalog_id   = azuread_access_package_catalog.eng.id
  display_name = "Engineering Contractor Bundle"
  description  = "Group + app access for contractors"
}

resource "azuread_access_package_assignment_policy" "internal" {
  access_package_id = azuread_access_package.contractor.id
  display_name      = "Internal employees"
  description       = "Manager approval, 90-day duration"

  requestor_settings {
    scope_type      = "AllExistingDirectoryMemberUsers"
    requests_accepted = true
  }

  approval_settings {
    approval_required = true
    approval_stage {
      approval_timeout_in_days = 14
      primary_approver {
        object_type = "requestorManager"
      }
    }
  }

  assignment_review_settings {
    enabled              = true
    review_frequency     = "quarterly"
    review_type          = "Manager"
    duration_in_days     = 25
    access_review_timeout_behavior = "removeAccess"
  }

  expiration_date           = null
  duration_until_expiration = "P90D"
}
